		}(g)
	}

	wg.Wait()

	all := make([]*Order, 0, (numBuyers+numSellers)*each)
	for _, lo := range buyOrders  { all = append(all, lo...) }
	for _, lo := range sellOrders { all = append(all, lo...) }
